// syncResourcePath maps resource names to their actual API endpoint paths.
// For REST APIs this is typically "/<resource>". For non-REST APIs (e.g., Steam)
// this preserves the actual endpoint path like "/ISteamApps/GetAppList/v2".
func syncResourcePath(resource string) (string, error) {
	paths := map[string]string{
		"account-activity":          "/2/account_activity/subscriptions/count",
		"activity":                  "/2/activity/stream",
		"activity-subscriptions":    "/2/activity/subscriptions",
		"articles":                  "/i/api/graphql/N1zzFzRPspT-sP9Q42n_bg/ArticleEntitiesSlice",
		"chat":                      "/2/chat/conversations",
		"compliance":                "/2/compliance/jobs",
		"connections":               "/2/connections",
		"dm-events":                 "/2/dm_events",
		"openapi-json":              "/2/openapi.json",
		"tweets":                    "/2/tweets/sample/stream",
		"tweets-search-webhooks":    "/2/tweets/search/webhooks",
		"usage":                     "/2/usage/tweets",
		"users":                     "/2/users/me",
		"users-personalized-trends": "/2/users/personalized_trends",
		"users-reposts-of-me":       "/2/users/reposts_of_me",
		"webhooks":                  "/2/webhooks",
	}
	if p, ok := paths[resource]; ok {
		return p, nil
	}
	return "", fmt.Errorf("unknown sync resource %q", resource)
}

